import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [projects, setProjects] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [editingProject, setEditingProject] = useState(null);
  const adminPassword = "admin123";

  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setProjects(res.data);
    } catch (err) { console.error(err); }
  };

  useEffect(() => { if (isLoggedIn) fetchData(); }, [isLoggedIn]);

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`http://localhost:5000/api/update-status/${editingProject._id}`, editingProject);
      setEditingProject(null);
      fetchData();
    } catch (err) { alert("Update failed!"); }
  };

  const handleMarkFullPaid = async (proj) => {
    if (window.confirm(`Mark ${proj.fullName} as Fully Paid?`)) {
      try {
        await axios.put(`http://localhost:5000/api/update-status/${proj._id}`, {
          ...proj, advancePaid: proj.totalBudget
        });
        fetchData();
      } catch (err) { alert("Failed!"); }
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="login-screen">
        <style>{`
          .login-screen { background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); height: 100vh; display: flex; align-items: center; justify-content: center; font-family: 'Inter', sans-serif; }
          .login-card { background: white; padding: 40px; border-radius: 20px; shadow: 0 10px 25px rgba(0,0,0,0.2); width: 350px; text-align: center; }
          .login-card h4 { font-weight: 800; color: #2d3748; margin-bottom: 25px; }
          .login-card input { border-radius: 10px; border: 2px solid #edf2f7; padding: 12px; margin-bottom: 20px; width: 100%; transition: 0.3s; }
          .login-card input:focus { border-color: #667eea; outline: none; }
          .login-btn { background: #667eea; color: white; border: none; padding: 12px; border-radius: 10px; width: 100%; font-weight: bold; cursor: pointer; }
        `}</style>
        <div className="login-card">
          <h4>Admin Portal</h4>
          <form onSubmit={(e) => { e.preventDefault(); if(password === adminPassword) setIsLoggedIn(true); else alert("Wrong!"); }}>
            <input type="password" placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} />
            <button className="login-btn">Unlock Dashboard</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="admin-container">
      <style>{`
        @import url('https://fonts.googleapis.com');
        body { background-color: #f7fafc; font-family: 'Inter', sans-serif; }
        .admin-container { padding: 40px; max-width: 1300px; margin: auto; }
        .dashboard-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 30px; }
        .dashboard-header h2 { font-weight: 800; color: #1a202c; letter-spacing: -1px; }
        
        .main-card { background: white; border-radius: 20px; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.1), 0 2px 4px -1px rgba(0,0,0,0.06); border: none; overflow: hidden; }
        .custom-table { width: 100%; border-collapse: collapse; }
        .custom-table thead { background: #1a202c; color: white; text-align: left; }
        .custom-table th { padding: 18px 25px; font-size: 12px; text-transform: uppercase; letter-spacing: 1px; }
        .custom-table td { padding: 20px 25px; border-bottom: 1px solid #edf2f7; vertical-align: middle; }
        .custom-table tr:hover { background-color: #f9fafb; }

        .client-name { font-weight: 700; color: #2d3748; font-size: 15px; }
        .service-tag { color: #667eea; font-weight: 600; font-size: 12px; text-transform: uppercase; }
        
        .progress-container { width: 120px; }
        .progress-bar-wrap { background: #edf2f7; border-radius: 10px; height: 8px; overflow: hidden; }
        .progress-fill { background: linear-gradient(90deg, #667eea 0%, #764ba2 100%); height: 100%; border-radius: 10px; }

        .paid-badge { background: #c6f6d5; color: #22543d; padding: 6px 12px; border-radius: 8px; font-weight: 700; font-size: 11px; display: inline-block; }
        .rem-text { color: #e53e3e; font-weight: 800; font-size: 14px; }
        
        .action-btn { border: 1px solid #e2e8f0; background: white; padding: 8px 15px; border-radius: 8px; font-size: 12px; font-weight: 600; cursor: pointer; transition: 0.2s; margin-right: 5px; }
        .action-btn:hover { background: #f7fafc; border-color: #cbd5e0; }
        .delete-btn { color: #e53e3e; border-color: #fed7d7; }
        .delete-btn:hover { background: #fff5f5; }

        .modal-overlay { position: fixed; top:0; left:0; width:100%; height:100%; background: rgba(0,0,0,0.5); display: flex; align-items: center; justify-content: center; z-index: 1000; }
        .modal-box { background: white; padding: 30px; border-radius: 20px; width: 450px; shadow: 0 20px 25px rgba(0,0,0,0.1); }
      `}</style>

      <div className="dashboard-header">
        <div>
          <h2>Project Control Center</h2>
          <span style={{color: '#718096'}}>Manage your workspace and financials</span>
        </div>
        <button className="action-btn delete-btn" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>

      <div className="main-card">
        <table className="custom-table">
          <thead>
            <tr>
              <th>Client & Project</th>
              <th>Work Progress</th>
              <th>Financials</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {projects.map((proj) => {
              const balance = Number(proj.totalBudget) - Number(proj.advancePaid);
              const isSettled = Number(proj.totalBudget) > 0 && balance <= 0;
              return (
                <tr key={proj._id}>
                  <td>
                    <div className="client-name">{proj.fullName}</div>
                    <div className="service-tag">{proj.serviceType}</div>
                  </td>
                  <td>
                    <div className="progress-container">
                      <div className="progress-bar-wrap">
                        <div className="progress-fill" style={{ width: `${proj.progress}%` }}></div>
                      </div>
                      <div style={{fontSize: '11px', fontWeight: 'bold', marginTop: '5px'}}>{proj.progress}% Done</div>
                    </div>
                  </td>
                  <td>
                    {isSettled ? (
                      <span className="paid-badge">✅ FULLY PAID</span>
                    ) : (
                      <div>
                        <div style={{fontSize: '12px', color: '#718096'}}>Remaining</div>
                        <div className="rem-text">₹{balance}</div>
                        <button className="action-btn" style={{color: '#27ae60', marginTop: '5px', fontSize: '10px'}} onClick={() => handleMarkFullPaid(proj)}>Mark Full Paid</button>
                      </div>
                    )}
                  </td>
                  <td className="text-end">
                    <button className="action-btn" onClick={() => setEditingProject(proj)}>Edit</button>
                    <button className="action-btn delete-btn" onClick={() => { if(window.confirm("Delete?")) axios.delete(`http://localhost:5000/api/delete-request/${proj._id}`).then(() => fetchData()) }}>Delete</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {editingProject && (
        <div className="modal-overlay">
          <div className="modal-box text-center">
            <h4 className="fw-bold mb-4">Edit Details</h4>
            <div className="row g-3">
              <div className="col-6">
                <label className="small d-block text-start fw-bold mb-1">Budget</label>
                <input type="number" className="form-control" value={editingProject.totalBudget} onChange={(e) => setEditingProject({...editingProject, totalBudget: e.target.value})} />
              </div>
              <div className="col-6">
                <label className="small d-block text-start fw-bold mb-1">Paid</label>
                <input type="number" className="form-control" value={editingProject.advancePaid} onChange={(e) => setEditingProject({...editingProject, advancePaid: e.target.value})} />
              </div>
            </div>
            <button className="login-btn mt-4" onClick={handleUpdate}>Save All Changes</button>
            <button className="action-btn mt-2 w-100" onClick={() => setEditingProject(null)}>Cancel</button>
          </div>
        </div>
      )}
    </div>
  );
}

export default Admin;
